import React, { useState, useMemo, useEffect } from 'react';
import { 
  Trash2, Edit2, Save, X, Quote, Plus, Settings, Activity, Users, 
  ChevronLeft, ChevronRight, Calendar, Camera, Maximize2, 
  UploadCloud, Layout, User, Clock, Lock, UserCircle, Target, AlertCircle, Lightbulb, UserCheck, UserX, History, Bookmark, Award, BarChart3, TrendingUp, CheckCircle2, ChevronRight as ChevronRightIcon, Link2, ExternalLink, Zap, Code, FileText, Bell, Info, Mail, MessageSquare
} from 'lucide-react';
import { UserData, Page } from '../App';
import { StudentProgress, WeeklyHighlight, Season, Notification, TeamMember } from '../types';
import CuratorDetail from './CuratorDetail';
import { TEAM_MEMBERS } from '../constants';

interface DashboardProps {
  user: UserData | null;
  studentsData: StudentProgress[];
  highlights: WeeklyHighlight[];
  onRemoveStudent: (id: string) => void;
  onUpdateProfile: (data: Partial<UserData>) => void;
  onUpdateStudent: (student: StudentProgress) => void;
  onAddProgress: (progress: StudentProgress) => void;
  onAddHighlight: (highlight: WeeklyHighlight) => void;
  onRemoveHighlight: (id: string) => void;
  activeSeasonId: string;
  seasons: Season[];
  notifications?: Notification[];
  onMarkRead?: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  studentsData, 
  highlights,
  onRemoveStudent, 
  onUpdateProfile, 
  onUpdateStudent, 
  onAddProgress,
  onAddHighlight,
  onRemoveHighlight,
  activeSeasonId,
  seasons,
  notifications = [],
  onMarkRead
}) => {
  const [activeTab, setActiveTab] = useState<'panel' | 'profile' | 'notifications'>('panel');
  const [selectedWeek, setSelectedWeek] = useState(1);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [viewingCurator, setViewingCurator] = useState<TeamMember | null>(null);

  const unreadCount = useMemo(() => notifications.filter(n => !n.isRead).length, [notifications]);

  // Profile Editing State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [profileForm, setProfileForm] = useState({
    name: user?.name || '',
    field: user?.field || '',
    longBio: user?.longBio || '',
    motivationQuote: user?.motivationQuote || '',
    skills: user?.skills?.join(', ') || ''
  });

  const handleSaveProfile = () => {
    onUpdateProfile({
      name: profileForm.name,
      field: profileForm.field,
      longBio: profileForm.longBio,
      motivationQuote: profileForm.motivationQuote,
      skills: profileForm.skills.split(',').map(s => s.trim()).filter(s => s !== '')
    });
    setIsEditingProfile(false);
  };

  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/20 text-green-400 border-green-500/30';
      case 'Bajarmadi': return 'bg-red-500/20 text-red-400 border-red-500/30';
      case 'Bajarilmoqda': return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
      case 'Kutilmoqda': return 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30';
      default: return 'bg-white/10 text-white border-white/20';
    }
  };

  const assignedCurator = useMemo(() => {
    if (!user?.assignedCuratorId) return null;
    return TEAM_MEMBERS.find(m => m.id === user.assignedCuratorId) || null;
  }, [user]);

  const myProgress = useMemo(() => {
    return studentsData.filter(p => p.studentName === user?.name && p.seasonId === activeSeasonId);
  }, [studentsData, user, activeSeasonId]);

  const curatorStudents = useMemo(() => {
    if (user?.role !== 'curator') return [];
    const base = studentsData.filter(s => s.curatorId === user.id);
    return base.filter(s => s.seasonId === activeSeasonId);
  }, [studentsData, user, activeSeasonId]);

  return (
    <section id="dashboard" className="py-10 md:py-20 bg-[#0a0a0c] min-h-screen">
      <div className="max-w-6xl mx-auto px-4">

        {/* Navigation Tabs (Only for Curators/Admins, Students get a Profile Card style) */}
        {user?.role === 'curator' && (
          <div className="flex justify-center mb-10">
            <div className="inline-flex p-1.5 bg-white/5 rounded-[2.5rem] border border-white/10 backdrop-blur-2xl">
              <button 
                onClick={() => setActiveTab('panel')}
                className={`flex items-center space-x-3 px-8 py-3 rounded-3xl text-[10px] font-black transition-all ${
                  activeTab === 'panel' ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
                }`}
              >
                <Activity className="w-4 h-4" />
                <span className="uppercase tracking-widest">Monitoring</span>
              </button>
              <button 
                onClick={() => setActiveTab('profile')}
                className={`flex items-center space-x-3 px-8 py-3 rounded-3xl text-[10px] font-black transition-all ${
                  activeTab === 'profile' ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
                }`}
              >
                <Settings className="w-4 h-4" />
                <span className="uppercase tracking-widest">Profil</span>
              </button>
              <button 
                onClick={() => setActiveTab('notifications')}
                className={`flex items-center space-x-3 px-8 py-3 rounded-3xl text-[10px] font-black transition-all relative ${
                  activeTab === 'notifications' ? 'bg-purple-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
                }`}
              >
                <Bell className="w-4 h-4" />
                <span className="uppercase tracking-widest">Xabarlar</span>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-[8px] flex items-center justify-center rounded-full font-black border-2 border-[#0a0a0c]">
                    {unreadCount}
                  </span>
                )}
              </button>
            </div>
          </div>
        )}

        {/* STUDENT PROFILE VIEW (Matches provided design) */}
        {user?.role === 'student' && (
          <div className="animate-in fade-in duration-700">
            <div className="bg-[#111114] rounded-[3rem] border border-white/5 p-8 md:p-16 shadow-2xl overflow-hidden relative">
              {/* Close/Action buttons top right */}
              <div className="absolute top-8 right-8 flex gap-4">
                <button className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center text-slate-500 hover:text-white border border-white/10 transition-all">
                  <X className="w-6 h-6" />
                </button>
              </div>

              {/* Profile Header */}
              <div className="flex flex-col md:flex-row gap-10 items-center md:items-start mb-16">
                <div className="w-48 h-48 rounded-[3.5rem] bg-[#1a1a1e] border-2 border-white/10 flex items-center justify-center text-indigo-500 text-7xl font-black shadow-inner overflow-hidden">
                  {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : user.name[0]}
                </div>

                <div className="flex-1 text-center md:text-left pt-2">
                  <div className="flex flex-wrap justify-center md:justify-start gap-3 mb-6">
                    <span className="px-5 py-1.5 bg-indigo-600/20 text-indigo-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-indigo-500/20">STUDENT</span>
                    <span className="px-5 py-1.5 bg-green-600/20 text-green-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-green-500/20">ACTIVE</span>
                  </div>

                  <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter mb-2 leading-none">{user.name}</h1>
                  <p className="text-2xl font-bold text-slate-500 tracking-tight mb-8">@{user.username}</p>

                  <div className="flex flex-wrap justify-center md:justify-start gap-4">
                    <div className="flex items-center gap-3 px-6 py-4 bg-white/5 rounded-2xl border border-white/10 text-slate-400 font-bold">
                       <Mail className="w-5 h-5 text-slate-600" />
                       <span className="text-sm">{user.email}</span>
                    </div>
                    <button className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-2xl shadow-indigo-600/30 hover:scale-105 active:scale-95 transition-all">
                       <MessageSquare className="w-5 h-5" />
                       XABAR YUBORISH
                    </button>
                  </div>
                </div>
              </div>

              <div className="h-px bg-white/5 w-full mb-16"></div>

              {/* Split Content */}
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
                {/* Left: Bio & Skills */}
                <div className="lg:col-span-5 space-y-12">
                  <div className="space-y-6">
                    <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3">
                      <FileText className="w-5 h-5 text-indigo-500" /> B I O
                    </h4>
                    <p className="text-xl text-slate-400 leading-relaxed font-medium italic">
                      "{user.longBio || "Ushbu o'quvchi o'zi haqida ma'lumot kiritmagan."}"
                    </p>
                  </div>

                  <div className="space-y-6">
                    <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3">
                      <Rocket className="w-5 h-5 text-indigo-500" /> K O' N I K M A L A R
                    </h4>
                    <div className="flex flex-wrap gap-2">
                       {user.skills?.length ? user.skills.map(s => (
                          <span key={s} className="px-4 py-2 bg-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 border border-white/5">{s}</span>
                       )) : <span className="text-slate-600 italic text-sm">Hozircha yo'q</span>}
                    </div>
                  </div>

                  {/* Curator Section */}
                  {assignedCurator && (
                    <div className="space-y-6">
                      <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3">
                        <UserCheck className="w-5 h-5 text-indigo-500" /> B U D D Y (Kurator)
                      </h4>
                      <button 
                        onClick={() => setViewingCurator(assignedCurator)}
                        className="w-full p-6 bg-indigo-600/5 border border-indigo-500/10 rounded-[2.5rem] flex items-center gap-6 group hover:bg-indigo-600/10 transition-all"
                      >
                        <div className="w-16 h-16 rounded-2xl bg-indigo-600/20 flex items-center justify-center overflow-hidden border border-indigo-500/20">
                           <img src={assignedCurator.avatar} className="w-full h-full object-cover" />
                        </div>
                        <div className="text-left">
                           <p className="text-xl font-black text-white leading-tight">{assignedCurator.name}</p>
                           <p className="text-[10px] font-black uppercase text-indigo-400 tracking-widest mt-1">{assignedCurator.role}</p>
                        </div>
                        <ChevronRightIcon className="ml-auto w-6 h-6 text-indigo-500 group-hover:translate-x-2 transition-transform" />
                      </button>
                    </div>
                  )}
                </div>

                {/* Right: Progress Table */}
                <div className="lg:col-span-7 space-y-10">
                   <div className="flex items-center justify-between">
                      <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3">
                        <TrendingUp className="w-5 h-5 text-indigo-500" /> M A V S U M I Y P R O G R E S S
                      </h4>
                      <span className="text-[9px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-600/10 px-4 py-2 rounded-xl">MAVSUM #1</span>
                   </div>

                   <div className="bg-[#1a1a1e] rounded-[2.5rem] border border-white/5 overflow-hidden shadow-xl">
                      <table className="w-full text-left">
                         <thead>
                            <tr className="bg-white/5 border-b border-white/5">
                               <th className="px-8 py-6 text-[10px] font-black text-slate-600 uppercase tracking-widest">HAFTA</th>
                               <th className="px-8 py-6 text-[10px] font-black text-slate-600 uppercase tracking-widest">MAQSAD</th>
                               <th className="px-8 py-6 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">HOLAT</th>
                            </tr>
                         </thead>
                         <tbody className="divide-y divide-white/5">
                            {myProgress.length > 0 ? myProgress.map(p => (
                               <tr key={p.id} className="hover:bg-white/[0.02] transition-colors">
                                  <td className="px-8 py-8">
                                     <span className="text-2xl font-black text-white tracking-tighter">Hafta #0{p.weekNumber}</span>
                                  </td>
                                  <td className="px-8 py-8">
                                     <p className="text-sm text-slate-400 font-medium leading-relaxed">{p.weeklyGoal}</p>
                                  </td>
                                  <td className="px-8 py-8 text-right">
                                     <span className={`inline-block px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border ${getStatusStyle(p.status)}`}>{p.status}</span>
                                  </td>
                               </tr>
                            )) : (
                               <tr><td colSpan={3} className="py-20 text-center text-slate-700 font-black uppercase tracking-widest text-xs">Hozircha ma'lumot yo'q</td></tr>
                            )}
                         </tbody>
                      </table>
                   </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* CURATOR MONITORING VIEW */}
        {user?.role === 'curator' && activeTab === 'panel' && (
          <div className="animate-in fade-in duration-500 space-y-16">
             <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-10">
                <div>
                   <h2 className="text-indigo-500 font-black tracking-[0.3em] uppercase text-[10px] mb-4 flex items-center gap-2"><Layout className="w-4 h-4" /> Boshqaruv Markazi</h2>
                   <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter leading-none">Monitoring</h1>
                </div>
                <div className="flex items-center justify-center p-2 glass rounded-[3rem] border border-white/10 self-center">
                    <button disabled={selectedWeek === 1} onClick={() => setSelectedWeek(w => w - 1)} className="p-5 text-slate-400 hover:text-white disabled:opacity-20 transition-all hover:bg-white/5 rounded-full"><ChevronLeft className="w-8 h-8" /></button>
                    <div className="px-16 text-center border-x border-white/5">
                      <p className="text-[10px] font-black uppercase text-slate-500 mb-1 tracking-widest">Hafta</p>
                      <p className="text-4xl font-black text-white tracking-tighter">#0{selectedWeek}</p>
                    </div>
                    <button disabled={selectedWeek === 4} onClick={() => setSelectedWeek(w => w + 1)} className="p-5 text-slate-400 hover:text-white disabled:opacity-20 transition-all hover:bg-white/5 rounded-full"><ChevronRight className="w-8 h-8" /></button>
                </div>
             </div>

             <div className="glass rounded-[3rem] border border-white/10 overflow-hidden shadow-2xl bg-[#0a0a0c]/50">
                <div className="w-full overflow-x-auto">
                   <table className="w-full text-left border-collapse table-fixed min-w-[1000px]">
                      <thead>
                         <tr className="bg-white/[0.04] border-b border-white/5">
                            <th className="w-[20%] px-10 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">O'quvchi</th>
                            <th className="w-[30%] px-4 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">Maqsad</th>
                            <th className="w-[15%] px-4 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Holat</th>
                            <th className="w-[15%] px-4 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Amallar</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-white/5">
                         {curatorStudents.filter(p => p.weekNumber === selectedWeek).length > 0 ? curatorStudents.filter(p => p.weekNumber === selectedWeek).map((item) => (
                           <tr key={item.id} className="hover:bg-indigo-600/[0.03] transition-colors">
                              <td className="px-10 py-10">
                                 <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-indigo-600/20 flex items-center justify-center font-black text-indigo-400 text-sm border border-indigo-500/10">{item.studentName[0]}</div>
                                    <span className="font-black text-white text-[15px]">{item.studentName}</span>
                                 </div>
                              </td>
                              <td className="px-4 py-10"><p className="text-[13px] text-slate-300 font-medium leading-relaxed">{item.weeklyGoal}</p></td>
                              <td className="px-4 py-10 text-center"><span className={`px-4 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest border ${getStatusStyle(item.status)}`}>{item.status}</span></td>
                              <td className="px-4 py-10 text-center">
                                 <button className="p-3 bg-white/5 rounded-xl hover:bg-white/10 text-slate-500 hover:text-white transition-all"><Edit2 className="w-5 h-5" /></button>
                              </td>
                           </tr>
                         )) : (
                            <tr><td colSpan={4} className="py-24 text-center text-slate-700 font-black uppercase tracking-widest text-xs">Hozircha ma'mulot kiritilmagan</td></tr>
                         )}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        )}

        {/* CURATOR DETAIL OVERLAY */}
        {viewingCurator && (
          <CuratorDetail 
            curator={viewingCurator} 
            onClose={() => setViewingCurator(null)} 
            studentsData={studentsData}
            highlights={highlights}
          />
        )}
      </div>
    </section>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { TeamMember, StudentProgress, WeeklyHighlight } from '../types';
import { X, ChevronLeft, Star, Quote, Users, Briefcase, Award, Info, Calendar, UserCheck, UserX, Activity, ChevronRight, Target, Camera, Image as ImageIcon, Maximize2, Zap, AlertCircle, Lightbulb, TrendingUp, Target as TargetIcon } from 'lucide-react';

interface CuratorDetailProps {
  curator: TeamMember;
  onClose: () => void;
  studentsData?: StudentProgress[];
  highlights?: WeeklyHighlight[];
}

const CuratorDetail: React.FC<CuratorDetailProps> = ({ curator, onClose, studentsData = [], highlights = [] }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'plans' | 'students'>('profile');
  const [selectedWeek, setSelectedWeek] = useState(1);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    document.documentElement.style.overflow = 'hidden';
    return () => { 
      document.body.style.overflow = ''; 
      document.documentElement.style.overflow = '';
    };
  }, []);

  const curatorStudents = studentsData
    .filter(item => item.curatorId === curator.id)
    .reduce((acc, current) => {
      const x = acc.find(item => item.studentName === current.studentName);
      if (!x) return acc.concat([current]);
      return acc;
    }, [] as StudentProgress[]);

  const filteredPlans = studentsData.filter(
    item => item.curatorId === curator.id && item.weekNumber === selectedWeek
  );

  const currentHighlights = highlights.filter(h => 
    h.weekNumber === selectedWeek && h.curatorId === curator.id
  );

  const formatMeetingDay = (val: string) => {
    if (!val) return "Belgilanmagan";
    try {
      const date = new Date(val);
      if (isNaN(date.getTime())) return val;
      return date.toLocaleString('uz-UZ', { weekday: 'short', day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
    } catch { return val; }
  };

  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/10 text-green-400 border-green-500/20';
      case 'Bajarmadi': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'Bajarilmoqda': return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
      case 'Kutilmoqda': return 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20';
      default: return 'bg-white/10 text-white border-white/20';
    }
  };

  return (
    <div className="fixed inset-0 z-[110] bg-[#0a0a0c] overflow-y-auto animate-in fade-in duration-300">
      <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
        <div className="absolute top-0 right-0 w-[400px] md:w-[800px] h-[400px] md:h-[800px] bg-indigo-600/10 blur-[100px] md:blur-[150px] rounded-full"></div>
      </div>

      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-12 py-8 md:py-20 min-h-screen">
        <div className="flex flex-col lg:flex-row justify-between items-center gap-6 mb-12 md:mb-16">
          <button onClick={onClose} className="w-full lg:w-auto flex items-center justify-center space-x-3 text-slate-400 hover:text-white transition-all bg-white/5 px-6 py-3.5 rounded-2xl border border-white/10 group"><ChevronLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" /><span className="font-bold uppercase text-[10px] tracking-widest">Orqaga</span></button>
          <div className="flex bg-white/5 p-1 rounded-2xl border border-white/5 w-full lg:w-auto">
            <button onClick={() => setActiveTab('profile')} className={`flex-1 lg:flex-none px-8 py-3 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all ${activeTab === 'profile' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>PROFİL</button>
            <button onClick={() => setActiveTab('students')} className={`flex-1 lg:flex-none px-8 py-3 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all ${activeTab === 'students' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>O'QUVCHILAR</button>
            <button onClick={() => setActiveTab('plans')} className={`flex-1 lg:flex-none px-8 py-3 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all ${activeTab === 'plans' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>MONITORING</button>
          </div>
        </div>

        {activeTab === 'profile' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 md:gap-12 animate-in fade-in duration-500 max-w-7xl mx-auto">
            <div className="lg:col-span-1">
              <div className="glass border border-white/10 rounded-[3rem] p-8 text-center">
                <div className="relative aspect-square rounded-[3rem] overflow-hidden mb-8 border-4 border-white/5 shadow-2xl mx-auto">
                  <img src={curator.avatar} alt={curator.name} className="w-full h-full object-cover" />
                </div>
                <h2 className="text-4xl font-black text-white mb-2 tracking-tighter">{curator.name}</h2>
                <p className="text-indigo-400 font-black uppercase tracking-[0.2em] text-xs mb-8">{curator.role}</p>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-6 bg-white/5 rounded-[2rem] border border-white/5">
                    <Users className="w-5 h-5 text-indigo-400 mx-auto mb-2" />
                    <p className="text-[9px] font-black uppercase text-slate-500 tracking-widest">O'QUVCHILAR</p>
                    <p className="text-2xl font-black text-white">{curatorStudents.length}</p>
                  </div>
                  <div className="p-6 bg-white/5 rounded-[2rem] border border-white/5">
                    <Star className="w-5 h-5 text-yellow-500 fill-current mx-auto mb-2" />
                    <p className="text-[9px] font-black uppercase text-slate-500 tracking-widest">REYTING</p>
                    <p className="text-2xl font-black text-white">5.0</p>
                  </div>
                </div>
              </div>
            </div>
            <div className="lg:col-span-2 space-y-8">
