                              </td>
                              <td className="px-4 py-10"><p className="text-[13px] text-slate-300 font-medium leading-relaxed">{item.weeklyGoal}</p></td>
                              <td className="px-4 py-10 text-center"><span className={`px-4 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest border ${getStatusStyle(item.status)}`}>{item.status}</span></td>
                              <td className="px-4 py-10 text-center">
                                 <button className="p-3 bg-white/5 rounded-xl hover:bg-white/10 text-slate-500 hover:text-white transition-all"><Edit2 className="w-5 h-5" /></button>
                              </td>
                           </tr>
                         )) : (
                            <tr><td colSpan={4} className="py-24 text-center text-slate-700 font-black uppercase tracking-widest text-xs">Hozircha ma'mulot kiritilmagan</td></tr>
                         )}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        )}

        {/* CURATOR DETAIL OVERLAY */}
        {viewingCurator && (
          <CuratorDetail 
            curator={viewingCurator} 
            onClose={() => setViewingCurator(null)} 
            studentsData={studentsData}
            highlights={highlights}
          />
        )}
      </div>
    </section>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Trash2, Edit2, Save, X, Quote, Plus, Settings, Activity, Users, 
  ChevronLeft, ChevronRight, Calendar, Camera, Maximize2, 
  UploadCloud, Layout, User, Clock, Lock, UserCircle, Target, AlertCircle, Lightbulb, UserCheck, UserX, History, Bookmark, Award, BarChart3, TrendingUp, CheckCircle2, ChevronRight as ChevronRightIcon, Link2, ExternalLink, Zap, Code, FileText, Bell, Info, Mail, MessageSquare, Rocket
