  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/20 text-green-400 border-green-500/30';
      case 'Bajarmadi': return 'bg-red-500/20 text-red-400 border-red-500/30';
      case 'Bajarilmoqda': return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
      case 'Kutilmoqda': return 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30';
      default: return 'bg-white/10 text-white border-white/20';
    }
