  const assignedCurator = useMemo(() => {
    if (!user?.assignedCuratorId) return null;
    return TEAM_MEMBERS.find(m => m.id === user.assignedCuratorId) || null;
  }, [user]);

  const myProgress = useMemo(() => {
    return studentsData.filter(p => p.studentName === user?.name && p.seasonId === activeSeasonId);
