                        <th className="px-10 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Holat</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                      {myProgress.length > 0 ? myProgress.map(p => (
                        <tr key={p.id} className="hover:bg-white/[0.02] transition-colors">
                          <td className="px-10 py-10">
                            <span className="text-2xl font-black text-white tracking-tighter">Hafta #0{p.weekNumber}</span>
                          </td>
                          <td className="px-10 py-10">
                            <p className="text-sm text-slate-400 font-medium leading-relaxed max-w-md">{p.weeklyGoal}</p>
                          </td>
                          <td className="px-10 py-10 text-center">
                            <span className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border ${getStatusStyle(p.status)}`}>{p.status}</span>
                          </td>
                        </tr>
                      )) : (
                        <tr><td colSpan={3} className="py-24 text-center text-slate-700 font-black uppercase tracking-widest text-xs">Hozircha ma'lumot yo'q</td></tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            ) : (
              <div className="glass rounded-[3rem] border border-white/10 overflow-hidden bg-[#111114]/50 shadow-2xl">
                 <div className="overflow-x-auto">
                   <table className="w-full text-left border-collapse table-fixed min-w-[1000px]">
                      <thead>
                         <tr className="bg-white/[0.04] border-b border-white/5">
                            <th className="w-[20%] px-10 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest">O'quvchi</th>
                            <th className="w-[45%] px-4 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest">Maqsad</th>
                            <th className="w-[15%] px-4 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Holat</th>
                            <th className="w-[20%] px-4 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Amallar</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-white/5">
                         {curatorStudents.filter(p => p.weekNumber === selectedWeek).length > 0 ? curatorStudents.filter(p => p.weekNumber === selectedWeek).map((item) => (
                           <tr key={item.id} className="hover:bg-indigo-600/[0.03] transition-colors">
                              <td className="px-10 py-10">
                                 <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 rounded-xl bg-indigo-600/20 flex items-center justify-center font-black text-indigo-400 text-xs border border-indigo-500/10">{item.studentName[0]}</div>
                                    <span className="font-black text-white text-sm">{item.studentName}</span>
                                 </div>
                              </td>
                              <td className="px-4 py-10"><p className="text-[13px] text-slate-300 font-medium leading-relaxed">{item.weeklyGoal}</p></td>
                              <td className="px-4 py-10 text-center"><span className={`px-4 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest border ${getStatusStyle(item.status)}`}>{item.status}</span></td>
                              <td className="px-4 py-10 text-center">
                                 <button className="p-2.5 bg-white/5 rounded-xl hover:bg-white/10 text-slate-500 hover:text-white transition-all"><Edit2 className="w-5 h-5" /></button>
                              </td>
                           </tr>
