                            <tr><td colSpan={4} className="py-24 text-center text-slate-700 font-black uppercase tracking-widest text-xs">Hozircha ma'mulot kiritilmagan</td></tr>
                         )}
                      </tbody>
                   </table>
                </div>
              </div>
            )}
          </div>
        )}

        {/* PROFILE TAB - Restored for all roles */}
        {activeTab === 'profile' && (
          <div className="animate-in fade-in duration-500 max-w-4xl mx-auto">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <div className="md:col-span-1">
                <div className="glass p-10 rounded-[3rem] border border-white/10 text-center relative overflow-hidden group">
                  <div className="w-32 h-32 rounded-[2.5rem] bg-[#1a1a1e] border-2 border-white/5 mx-auto mb-8 flex items-center justify-center text-indigo-500 text-5xl font-black relative overflow-hidden">
                    {user?.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : user?.name[0]}
                    <button className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <Camera className="w-8 h-8 text-white" />
                    </button>
                  </div>
                  <h3 className="text-3xl font-black text-white mb-1 tracking-tight">{user?.name}</h3>
                  <p className="text-slate-500 font-bold mb-8 italic">@{user?.username}</p>

                  <div className="pt-8 border-t border-white/5 space-y-4">
