                          <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Soha</p>
                          <p className="text-xl font-bold text-white">{user?.field || 'Belgilanmagan'}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Email</p>
                          <p className="text-xl font-bold text-white">{user?.email}</p>
                        </div>
                      </div>
                      <div>
                        <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Tarjimayi hol</p>
                        <p className="text-sm text-slate-400 leading-relaxed italic">{user?.longBio || 'Bio kiritilmagan'}</p>
                      </div>
                      <div>
                        <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-4 ml-1">Konyakmalar</p>
                        <div className="flex flex-wrap gap-2">
                          {user?.skills?.map(s => (
                            <span key={s} className="px-3 py-1.5 bg-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 border border-white/5">{s}</span>
                          )) || <span className="text-slate-700 italic text-xs">Hozircha yo'q</span>}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* NOTIFICATIONS TAB */}
        {activeTab === 'notifications' && (
           <div className="animate-in fade-in duration-500 max-w-2xl mx-auto space-y-6">
              {notifications.length > 0 ? notifications.map(notif => (
                <div key={notif.id} className={`glass p-8 rounded-[2.5rem] border border-white/5 relative group transition-all ${notif.isRead ? 'opacity-60' : 'border-indigo-500/30'}`}>
                   {!notif.isRead && (
                      <div className="absolute top-8 right-8 w-2 h-2 bg-indigo-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(79,70,229,0.8)]"></div>
                   )}
                   <div className="flex items-start gap-5">
                      <div className={`p-3 rounded-2xl ${notif.type === 'success' ? 'bg-green-500/10 text-green-500' : 'bg-indigo-500/10 text-indigo-500'}`}>
                         <Bell className="w-5 h-5" />
                      </div>
                      <div className="flex-1">
                         <div className="flex justify-between items-center mb-2">
                            <h4 className="text-xl font-black text-white tracking-tight">{notif.title}</h4>
                            <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">
                               {new Date(notif.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                         </div>
                         <p className="text-sm text-slate-400 leading-relaxed mb-6">{notif.message}</p>
                         {!notif.isRead && onMarkRead && (
                            <button onClick={() => onMarkRead(notif.id)} className="text-[9px] font-black uppercase tracking-widest text-indigo-400 hover:text-white transition-colors flex items-center gap-2">
                               <CheckCircle2 className="w-3 h-3" /> O'qilgan deb belgilash
                            </button>
                         )}
                      </div>
                   </div>
                </div>
              )) : (
                <div className="py-24 text-center glass rounded-[3rem] border-dashed border-2 border-white/5">
                   <p className="text-sm font-black text-slate-700 uppercase tracking-widest">Xabarlar mavjud emas</p>
                </div>
              )}
           </div>
        )}

        {/* CURATOR DETAIL OVERLAY */}
        {viewingCurator && (
          <CuratorDetail 
            curator={viewingCurator} 
            onClose={() => setViewingCurator(null)} 
            studentsData={studentsData}
            highlights={highlights}
          />
        )}
      </div>
    </section>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
