              <div>
                <h2 className="text-indigo-500 font-black tracking-[0.3em] uppercase text-[10px] mb-3">Monitoring Markazi</h2>
                <h1 className="text-5xl md:text-7xl font-black text-white tracking-tighter">Faoliyat</h1>
              </div>
              <div className="flex items-center p-1 bg-white/5 rounded-2xl border border-white/10">
                <button disabled={selectedWeek === 1} onClick={() => setSelectedWeek(w => w - 1)} className="p-3 text-slate-500 hover:text-white disabled:opacity-20"><ChevronLeft className="w-6 h-6" /></button>
                <div className="px-6 text-center border-x border-white/5">
                   <p className="text-[9px] font-black uppercase text-slate-500 mb-0.5 tracking-widest">Hafta</p>
