              </div>
            </div>

            {/* If Student: Show own progress. If Curator: Show student list */}
            {user?.role === 'student' ? (
              <div className="glass rounded-[3rem] border border-white/10 overflow-hidden bg-[#111114]/50 shadow-2xl">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="bg-white/5 border-b border-white/10">
                        <th className="px-10 py-8 text-[10px] font-black text-slate-500 uppercase tracking-widest">Hafta</th>
