                  </div>
                  <h3 className="text-3xl font-black text-white mb-1 tracking-tight">{user?.name}</h3>
                  <p className="text-slate-500 font-bold mb-8 italic">@{user?.username}</p>

                  <div className="pt-8 border-t border-white/5 space-y-4">
                    <div className="flex justify-between items-center px-4">
                      <span className="text-[10px] font-black uppercase text-slate-600 tracking-widest">Lavozim</span>
                      <span className="px-3 py-1 bg-indigo-600/10 text-indigo-400 rounded-lg text-[10px] font-black uppercase tracking-widest border border-indigo-500/20">{user?.role}</span>
                    </div>
                    <div className="flex justify-between items-center px-4">
                      <span className="text-[10px] font-black uppercase text-slate-600 tracking-widest">Holat</span>
                      <span className="px-3 py-1 bg-green-600/10 text-green-400 rounded-lg text-[10px] font-black uppercase tracking-widest border border-green-500/20">Active</span>
                    </div>
                  </div>
                </div>

                {assignedCurator && (
                  <button 
                    onClick={() => setViewingCurator(assignedCurator)}
                    className="w-full mt-6 p-6 glass border border-white/5 rounded-[2.5rem] flex items-center gap-5 hover:border-indigo-500/30 transition-all text-left group"
                  >
                    <div className="w-12 h-12 rounded-xl bg-indigo-600/20 flex items-center justify-center overflow-hidden">
                       <img src={assignedCurator.avatar} className="w-full h-full object-cover" />
                    </div>
                    <div>
                       <p className="text-sm font-black text-white leading-none">Buddy: {assignedCurator.name}</p>
                       <p className="text-[10px] font-bold text-slate-500 mt-1 uppercase tracking-widest">Ustozni ko'rish</p>
                    </div>
                    <ChevronRightIcon className="ml-auto w-4 h-4 text-slate-700 group-hover:text-indigo-400" />
                  </button>
                )}
              </div>

              <div className="md:col-span-2 space-y-8">
                <div className="glass p-10 rounded-[3rem] border border-white/10 relative">
                  <div className="flex justify-between items-center mb-10">
                    <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.3em] flex items-center gap-3">
                      <UserCircle className="w-5 h-5 text-indigo-500" /> Shaxsiy Ma'lumotlar
                    </h4>
                    <button 
                      onClick={() => setIsEditingProfile(!isEditingProfile)}
                      className="text-indigo-400 hover:text-white transition-colors"
                    >
                      {isEditingProfile ? <X className="w-5 h-5" /> : <Edit2 className="w-5 h-5" />}
                    </button>
                  </div>

                  {isEditingProfile ? (
                    <div className="space-y-6">
                      <div className="grid grid-cols-2 gap-6">
                        <div className="space-y-2">
                          <label className="text-[9px] font-black uppercase text-slate-600 ml-4">Ism</label>
                          <input type="text" value={profileForm.name} onChange={e => setProfileForm({...profileForm, name: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-white text-sm outline-none focus:border-indigo-600" />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[9px] font-black uppercase text-slate-600 ml-4">Soha</label>
                          <input type="text" value={profileForm.field} onChange={e => setProfileForm({...profileForm, field: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-white text-sm outline-none focus:border-indigo-600" />
                        </div>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black uppercase text-slate-600 ml-4">Bio</label>
                        <textarea value={profileForm.longBio} onChange={e => setProfileForm({...profileForm, longBio: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-white text-sm outline-none focus:border-indigo-600 h-32 resize-none" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black uppercase text-slate-600 ml-4">Ko'nikmalar (vergul bilan)</label>
                        <input type="text" value={profileForm.skills} onChange={e => setProfileForm({...profileForm, skills: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-white text-sm outline-none focus:border-indigo-600" />
                      </div>
                      <button onClick={handleSaveProfile} className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Saqlash</button>
                    </div>
                  ) : (
                    <div className="space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div>
                          <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Soha</p>
                          <p className="text-xl font-bold text-white">{user?.field || 'Belgilanmagan'}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Email</p>
                          <p className="text-xl font-bold text-white">{user?.email}</p>
                        </div>
                      </div>
                      <div>
                        <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-2 ml-1">Tarjimayi hol</p>
                        <p className="text-sm text-slate-400 leading-relaxed italic">{user?.longBio || 'Bio kiritilmagan'}</p>
                      </div>
                      <div>
                        <p className="text-[9px] font-black uppercase text-slate-600 tracking-widest mb-4 ml-1">Konyakmalar</p>
                        <div className="flex flex-wrap gap-2">
                          {user?.skills?.map(s => (
                            <span key={s} className="px-3 py-1.5 bg-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 border border-white/5">{s}</span>
                          )) || <span className="text-slate-700 italic text-xs">Hozircha yo'q</span>}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* NOTIFICATIONS TAB */}
        {activeTab === 'notifications' && (
           <div className="animate-in fade-in duration-500 max-w-2xl mx-auto space-y-6">
              {notifications.length > 0 ? notifications.map(notif => (
                <div key={notif.id} className={`glass p-8 rounded-[2.5rem] border border-white/5 relative group transition-all ${notif.isRead ? 'opacity-60' : 'border-indigo-500/30'}`}>
                   {!notif.isRead && (
                      <div className="absolute top-8 right-8 w-2 h-2 bg-indigo-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(79,70,229,0.8)]"></div>
                   )}
                   <div className="flex items-start gap-5">
                      <div className={`p-3 rounded-2xl ${notif.type === 'success' ? 'bg-green-500/10 text-green-500' : 'bg-indigo-500/10 text-indigo-500'}`}>
                         <Bell className="w-5 h-5" />
                      </div>
                      <div className="flex-1">
                         <div className="flex justify-between items-center mb-2">
                            <h4 className="text-xl font-black text-white tracking-tight">{notif.title}</h4>
                            <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">
                               {new Date(notif.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                         </div>
                         <p className="text-sm text-slate-400 leading-relaxed mb-6">{notif.message}</p>
                         {!notif.isRead && onMarkRead && (
                            <button onClick={() => onMarkRead(notif.id)} className="text-[9px] font-black uppercase tracking-widest text-indigo-400 hover:text-white transition-colors flex items-center gap-2">
                               <CheckCircle2 className="w-3 h-3" /> O'qilgan deb belgilash
                            </button>
                         )}
                      </div>
                   </div>
                </div>
              )) : (
                <div className="py-24 text-center glass rounded-[3rem] border-dashed border-2 border-white/5">
                   <p className="text-sm font-black text-slate-700 uppercase tracking-widest">Xabarlar mavjud emas</p>
                </div>
              )}
           </div>
        )}

        {/* CURATOR DETAIL OVERLAY */}
        {viewingCurator && (
          <CuratorDetail 
            curator={viewingCurator} 
            onClose={() => setViewingCurator(null)} 
            studentsData={studentsData}
            highlights={highlights}
          />
        )}
      </div>
    </section>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Trash2, Edit2, Save, X, Quote, Plus, Settings, Activity, Users, 
  ChevronLeft, ChevronRight, Calendar, Camera, Maximize2, 
  UploadCloud, Layout, User, Clock, Lock, UserCircle, Target, AlertCircle, Lightbulb, UserCheck, UserX, History, Bookmark, Award, BarChart3, TrendingUp, CheckCircle2, ChevronRight as ChevronRightIcon, Link2, ExternalLink, Zap, Code, FileText, Bell, Info, Mail, MessageSquare, Rocket
} from 'lucide-react';
import { UserData, Page } from '../App';
import { StudentProgress, WeeklyHighlight, Season, Notification, TeamMember } from '../types';
import CuratorDetail from './CuratorDetail';
import { TEAM_MEMBERS } from '../constants';

interface DashboardProps {
  user: UserData | null;
  studentsData: StudentProgress[];
  highlights: WeeklyHighlight[];
  onRemoveStudent: (id: string) => void;
  onUpdateProfile: (data: Partial<UserData>) => void;
  onUpdateStudent: (student: StudentProgress) => void;
  onAddProgress: (progress: StudentProgress) => void;
  onAddHighlight: (highlight: WeeklyHighlight) => void;
  onRemoveHighlight: (id: string) => void;
  activeSeasonId: string;
  seasons: Season[];
  notifications?: Notification[];
  onMarkRead?: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  studentsData, 
  highlights,
  onRemoveStudent, 
  onUpdateProfile, 
  onUpdateStudent, 
  onAddProgress,
  onAddHighlight,
  onRemoveHighlight,
  activeSeasonId,
  seasons,
  notifications = [],
  onMarkRead
}) => {
  const [activeTab, setActiveTab] = useState<'panel' | 'profile' | 'notifications'>('panel');
  const [selectedWeek, setSelectedWeek] = useState(1);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [viewingCurator, setViewingCurator] = useState<TeamMember | null>(null);

  const unreadCount = useMemo(() => notifications.filter(n => !n.isRead).length, [notifications]);

  // Profile Editing State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [profileForm, setProfileForm] = useState({
    name: user?.name || '',
    field: user?.field || '',
    longBio: user?.longBio || '',
    motivationQuote: user?.motivationQuote || '',
    skills: user?.skills?.join(', ') || ''
  });

  useEffect(() => {
    if (user) {
      setProfileForm({
        name: user.name || '',
        field: user.field || '',
        longBio: user.longBio || '',
        motivationQuote: user.motivationQuote || '',
        skills: user.skills?.join(', ') || ''
      });
    }
  }, [user]);

  const handleSaveProfile = () => {
    onUpdateProfile({
      name: profileForm.name,
      field: profileForm.field,
      longBio: profileForm.longBio,
      motivationQuote: profileForm.motivationQuote,
      skills: profileForm.skills.split(',').map(s => s.trim()).filter(s => s !== '')
    });
    setIsEditingProfile(false);
  };

  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/20 text-green-400 border-green-500/30';
      case 'Bajarmadi': return 'bg-red-500/20 text-red-400 border-red-500/30';
      case 'Bajarilmoqda': return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
      case 'Kutilmoqda': return 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30';
      default: return 'bg-white/10 text-white border-white/20';
    }
  };

  const assignedCurator = useMemo(() => {
    if (!user?.assignedCuratorId) return null;
    return TEAM_MEMBERS.find(m => m.id === user.assignedCuratorId) || null;
  }, [user]);

  const myProgress = useMemo(() => {
    return studentsData.filter(p => p.studentName === user?.name && p.seasonId === activeSeasonId);
  }, [studentsData, user, activeSeasonId]);

  const curatorStudents = useMemo(() => {
    if (user?.role !== 'curator') return [];
    const base = studentsData.filter(s => s.curatorId === user.id);
    return base.filter(s => s.seasonId === activeSeasonId);
  }, [studentsData, user, activeSeasonId]);

  return (
    <section id="dashboard" className="py-10 md:py-20 bg-[#0a0a0c] min-h-screen">
      <div className="max-w-6xl mx-auto px-4">

        {/* Navigation Tabs - Restored for all roles */}
        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-white/5 rounded-[2.5rem] border border-white/10 backdrop-blur-2xl">
            <button 
              onClick={() => setActiveTab('panel')}
              className={`flex items-center space-x-3 px-8 py-3 rounded-3xl text-[10px] font-black transition-all ${
                activeTab === 'panel' ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
              }`}
            >
