interface AdminPanelProps {
  user: UserData | null;
  allUsers: UserData[];
  allProgress: StudentProgress[];
  onDeleteUser: (userId: string) => void;
  onChangeRole: (userId: string, newRole: 'student' | 'curator' | 'admin') => void;
  onUpdateProgress: (progress: StudentProgress) => void;
  onApproveUser: (userId: string) => void;
  onChangeStatus?: (userId: string, status: 'active' | 'inactive' | 'pending') => void;
  isRegistrationOpen: boolean;
  onToggleRegistration: () => void;
  seasons: Season[];
  activeSeasonId: string;
  onSwitchSeason: (id: string) => void;
  onStartNewSeason: () => void;
  onSendNotification: (notif: Notification) => void;
}

const ITEMS_PER_PAGE = 15;

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  user, allUsers, allProgress, onDeleteUser, onChangeRole, onApproveUser, onChangeStatus,
  isRegistrationOpen, onToggleRegistration, seasons, activeSeasonId, onSwitchSeason, onStartNewSeason, onSendNotification
}) => {
  const [activeTab, setActiveTab] = useState<'stats' | 'monitoring' | 'users' | 'requests' | 'seasons' | 'messages' | 'settings'>('monitoring');

  const [usersSearchQuery, setUsersSearchQuery] = useState('');
  const [usersFilterRole, setUsersFilterRole] = useState<'all' | 'student' | 'curator' | 'admin'>('all');
  const [usersPage, setUsersPage] = useState(1);

  const [monitoringWeek, setMonitoringWeek] = useState(1);
  const [monitoringSearch, setMonitoringSearch] = useState('');
  const [monitoringCuratorFilter, setMonitoringCuratorFilter] = useState('all');
  const [monitoringStatusFilter, setMonitoringStatusFilter] = useState('all');
  const [monitoringAttendanceFilter, setMonitoringAttendanceFilter] = useState<'all' | 'attended' | 'not-attended'>('all');
  const [monitoringPage, setMonitoringPage] = useState(1);

  const [selectedUserForView, setSelectedUserForView] = useState<UserData | null>(null);
  const [isDirectMessaging, setIsDirectMessaging] = useState(false);
  const [directMessageForm, setDirectMessageForm] = useState({ title: '', message: '', type: 'info' as Notification['type'] });

  const [messageForm, setMessageForm] = useState({
    title: '',
    message: '',
    type: 'info' as Notification['type'],
    targetRole: 'all' as Notification['targetRole']
  });
  const [isSending, setIsSending] = useState(false);

  useEffect(() => {
    if (selectedUserForView) {
      document.body.style.overflow = 'hidden';
      document.documentElement.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
      setIsDirectMessaging(false);
    }
    return () => {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
    };
  }, [selectedUserForView]);

  const [isSavingSettings, setIsSavingSettings] = useState(false);
  const [notificationSettings, setNotificationSettings] = useState({
    adminEmail: user?.email || '',
    onNewCuratorRequest: true,
    onGoalCompleted: true,
    onSeasonStart: true
  });

  useEffect(() => setUsersPage(1), [usersSearchQuery, usersFilterRole]);
  useEffect(() => setMonitoringPage(1), [monitoringSearch, monitoringCuratorFilter, monitoringStatusFilter, monitoringWeek, monitoringAttendanceFilter]);

  if (user?.role !== 'admin') {
    return (
      <div className="min-h-[70vh] flex items-center justify-center bg-[#0a0a0c]">
        <div className="text-center p-12 glass rounded-3xl border border-red-500/20">
          <ShieldAlert className="w-20 h-20 text-red-500 mx-auto mb-6" />
          <h2 className="text-4xl font-black text-white mb-4">Kirish Taqiqlandi</h2>
          <p className="text-slate-400">Sizda ushbu sahifani ko'rish uchun ruxsat yo'q.</p>
        </div>
      </div>
    );
  }

  const curatorsList = useMemo(() => allUsers.filter(u => u.role === 'curator'), [allUsers]);
  const approvedCurators = useMemo(() => curatorsList.filter(u => u.status === 'active'), [curatorsList]);
  const pendingUsers = useMemo(() => allUsers.filter(u => u.status === 'pending'), [allUsers]);

  const stats = useMemo(() => ({
    curatorsCount: approvedCurators.length,
    pendingCount: pendingUsers.length,
    studentsCount: allUsers.filter(u => u.role === 'student').length,
    totalPlans: allProgress.length
  }), [approvedCurators, pendingUsers, allUsers, allProgress]);

  const filteredUsers = useMemo(() => {
    return allUsers.filter(u => {
      const matchesSearch = u.name.toLowerCase().includes(usersSearchQuery.toLowerCase()) || 
                           u.username.toLowerCase().includes(usersSearchQuery.toLowerCase());
      const matchesRole = usersFilterRole === 'all' || u.role === usersFilterRole;
      return matchesSearch && matchesRole;
    });
  }, [allUsers, usersSearchQuery, usersFilterRole]);

  const totalUsersPages = Math.ceil(filteredUsers.length / ITEMS_PER_PAGE);
  const paginatedUsers = useMemo(() => {
    const start = (usersPage - 1) * ITEMS_PER_PAGE;
    return filteredUsers.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredUsers, usersPage]);

  const seasonProgress = useMemo(() => {
    return allProgress.filter(p => p.seasonId === activeSeasonId);
  }, [allProgress, activeSeasonId]);

  const filteredMonitoring = useMemo(() => {
    return seasonProgress.filter(p => {
      const matchesWeek = p.weekNumber === monitoringWeek;
      const matchesSearch = p.studentName.toLowerCase().includes(monitoringSearch.toLowerCase());
      const matchesCurator = monitoringCuratorFilter === 'all' || p.curatorId === monitoringCuratorFilter;
      const matchesStatus = monitoringStatusFilter === 'all' || p.status === monitoringStatusFilter;
      const matchesAttendance = monitoringAttendanceFilter === 'all' || 
                               (monitoringAttendanceFilter === 'attended' ? p.attended === true : p.attended === false);
      return matchesWeek && matchesSearch && matchesCurator && matchesStatus && matchesAttendance;
    });
  }, [seasonProgress, monitoringWeek, monitoringSearch, monitoringCuratorFilter, monitoringStatusFilter, monitoringAttendanceFilter]);

  const totalMonitoringPages = Math.ceil(filteredMonitoring.length / ITEMS_PER_PAGE);
  const paginatedMonitoring = useMemo(() => {
    const start = (monitoringPage - 1) * ITEMS_PER_PAGE;
    return filteredMonitoring.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredMonitoring, monitoringPage]);

  // Jadval uchun Progress holati
  const getProgressStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/10 text-green-400 border-green-500/20';
      case 'Bajarmadi': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'Bajarilmoqda': return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
      case 'Kutilmoqda': return 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20';
      default: return 'bg-white/10 text-white border-white/20';
    }
  };

  // Kuratorlar uchun foydalanuvchi statusi
  const getUserStatusStyle = (status: string) => {
    switch(status) {
      case 'active': return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20';
      case 'inactive': return 'bg-rose-500/10 text-rose-400 border-rose-500/20';
      case 'pending': return 'bg-amber-500/10 text-amber-400 border-amber-500/20';
      default: return 'bg-slate-500/10 text-slate-400 border-slate-500/20';
    }
  };

  const getRoleStyle = (role: string) => {
    switch(role) {
      case 'admin': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'curator': return 'bg-purple-500/10 text-purple-400 border-purple-500/20';
      default: return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
    }
  };

  const handleSaveNotificationSettings = async () => {
    setIsSavingSettings(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    setIsSavingSettings(false);
  };

  const handleSendMessage = async () => {
    if (!messageForm.title || !messageForm.message) return;
    setIsSending(true);
    await new Promise(resolve => setTimeout(resolve, 800));
    onSendNotification({
      id: Math.random().toString(36).substr(2, 9),
      title: messageForm.title,
      message: messageForm.message,
      type: messageForm.type,
      targetRole: messageForm.targetRole,
      timestamp: new Date().toISOString(),
      isRead: false,
      sender: 'Admin'
    });
    setMessageForm({ title: '', message: '', type: 'info', targetRole: 'all' });
    setIsSending(false);
    alert('Xabar muvaffaqiyatli yuborildi!');
  };

  const handleSendDirectMessage = async () => {
    if (!selectedUserForView || !directMessageForm.title || !directMessageForm.message) return;
    setIsSending(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    onSendNotification({
      id: Math.random().toString(36).substr(2, 9),
      title: directMessageForm.title,
      message: directMessageForm.message,
      type: directMessageForm.type,
      targetRole: 'all',
      targetUserId: selectedUserForView.id,
      timestamp: new Date().toISOString(),
      isRead: false,
      sender: 'Admin'
    });
    setDirectMessageForm({ title: '', message: '', type: 'info' });
    setIsDirectMessaging(false);
    setIsSending(false);
    alert(`${selectedUserForView.name} uchun xabar yuborildi!`);
  };

  const getAssignedCurator = (student: UserData | null) => {
    if (!student || student.role !== 'student') return null;
    return allUsers.find(u => u.id === student.assignedCuratorId) || null;
  };

  const getAssignedStudents = (curator: UserData | null) => {
    if (!curator || curator.role !== 'curator') return [];
    return allUsers.filter(u => u.assignedCuratorId === curator.id);
  };

  return (
    <section className="py-10 md:py-20 bg-[#0a0a0c] min-h-screen">
      <div className="max-w-[1700px] mx-auto px-4 lg:px-10">

        <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-10 mb-16">
          <div className="text-center xl:text-left">
            <h2 className="text-indigo-500 font-black tracking-[0.5em] uppercase text-[10px] mb-4 flex items-center justify-center xl:justify-start gap-3"><Shield className="w-4 h-4" /> Global Platform Admin</h2>
            <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter leading-none">Buddy<span className="text-slate-800">Panel</span></h1>
          </div>

          <div className="flex flex-wrap justify-center p-1.5 bg-white/5 rounded-[3rem] border border-white/10 backdrop-blur-3xl shadow-2xl overflow-hidden relative">
            {(['stats', 'monitoring', 'users', 'requests', 'seasons', 'messages', 'settings'] as const).map(tab => (
              <button 
                key={tab} onClick={() => setActiveTab(tab)}
                className={`px-6 md:px-8 py-4 md:py-5 rounded-[2rem] text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2 relative ${
                  activeTab === tab ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/40' : 'text-slate-500 hover:text-white'
                }`}
              >
                {tab === 'stats' ? 'Analitika' : tab === 'monitoring' ? 'Monitoring' : tab === 'users' ? 'A\'zolar' : tab === 'requests' ? 'So\'rovlar' : tab === 'seasons' ? 'Mavsumlar' : tab === 'messages' ? 'Xabarlar' : 'Sozlamalar'}
                {tab === 'requests' && stats.pendingCount > 0 && (
                   <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-[9px] flex items-center justify-center rounded-full border-2 border-[#0a0a0c]">{stats.pendingCount}</span>
                )}
              </button>
            ))}
          </div>
        </div>

        {activeTab === 'stats' && (
          <div className="animate-in fade-in duration-500 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
            <div className="p-8 bg-indigo-600/10 border border-indigo-500/20 rounded-[2.5rem] relative overflow-hidden">
              <Users className="w-10 h-10 text-indigo-400 mb-4" />
              <h3 className="text-4xl font-black text-white mb-1">{stats.studentsCount}</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">O'quvchilar</p>
            </div>
            <div className="p-8 bg-purple-600/10 border border-purple-500/20 rounded-[2.5rem] relative overflow-hidden">
              <Briefcase className="w-10 h-10 text-purple-400 mb-4" />
              <h3 className="text-4xl font-black text-white mb-1">{stats.curatorsCount}</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Kuratorlar</p>
            </div>
             <div className="p-8 bg-green-600/10 border border-green-500/20 rounded-[2.5rem] relative overflow-hidden">
              <Target className="w-10 h-10 text-green-400 mb-4" />
              <h3 className="text-4xl font-black text-white mb-1">{stats.totalPlans}</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Jami Rejalar</p>
            </div>
             <div className="p-8 bg-orange-600/10 border border-orange-500/20 rounded-[2.5rem] relative overflow-hidden">
              <Clock className="w-10 h-10 text-orange-400 mb-4" />
              <h3 className="text-4xl font-black text-white mb-1">{stats.pendingCount}</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Kutilmoqda</p>
            </div>
          </div>
        )}

        {activeTab === 'monitoring' && (
          <div className="animate-in fade-in duration-500 space-y-12">
             <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-10">
                <div>
                   <h2 className="text-indigo-500 font-black tracking-[0.3em] uppercase text-[10px] mb-4 flex items-center gap-2"><Activity className="w-4 h-4" /> Global Monitoring</h2>
                   <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter">Hafta #0{monitoringWeek}</h1>
                   <p className="text-indigo-400 font-bold uppercase tracking-widest text-xs mt-4">Mavsum #{activeSeasonId} - {filteredMonitoring.length} ta yozuv topildi</p>
                </div>
                <div className="flex items-center justify-center p-2 glass rounded-[3rem] border border-white/10 self-center">
                    <button disabled={monitoringWeek === 1} onClick={() => setMonitoringWeek(w => w - 1)} className="p-5 text-slate-400 hover:text-white disabled:opacity-20 transition-all hover:bg-white/5 rounded-[2rem]"><ChevronLeft className="w-8 h-8" /></button>
                    <div className="px-16 text-center border-x border-white/5"><p className="text-[10px] font-black uppercase text-slate-500 mb-1 tracking-widest">Hafta</p><p className="text-4xl font-black text-white tracking-tighter">#0{monitoringWeek}</p></div>
                    <button disabled={monitoringWeek === 4} onClick={() => setMonitoringWeek(w => w + 1)} className="p-5 text-slate-400 hover:text-white disabled:opacity-20 transition-all hover:bg-white/5 rounded-[2rem]"><ChevronRight className="w-8 h-8" /></button>
                </div>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 bg-[#121214] p-8 rounded-[3rem] border border-white/5 shadow-2xl">
                <div className="relative group"><Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-indigo-500 transition-colors" /><input type="text" placeholder="O'quvchini qidirish..." className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl py-4 pl-14 pr-6 text-white text-sm outline-none focus:border-indigo-600 transition-all" value={monitoringSearch} onChange={e => setMonitoringSearch(e.target.value)} /></div>
                <div className="relative group"><Users className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-indigo-500 transition-colors" /><select className="w-full bg-[#1a1a1e] border border-white/10 rounded-2xl py-4 pl-14 pr-6 text-white text-sm outline-none focus:border-indigo-600 transition-all appearance-none cursor-pointer" value={monitoringCuratorFilter} onChange={e => setMonitoringCuratorFilter(e.target.value)}><option value="all">Barcha Kuratorlar</option>{approvedCurators.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></div>
                <div className="relative group"><Filter className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-indigo-500 transition-colors" /><select className="w-full bg-[#1a1a1e] border border-white/10 rounded-2xl py-4 pl-14 pr-6 text-white text-sm outline-none focus:border-indigo-600 transition-all appearance-none cursor-pointer" value={monitoringStatusFilter} onChange={e => setMonitoringStatusFilter(e.target.value)}><option value="all">Barcha Holatlar</option><option value="Hal qilindi">Hal qilindi</option><option value="Bajarilmoqda">Bajarilmoqda</option><option value="Kutilmoqda">Kutilmoqda</option><option value="Bajarmadi">Bajarmadi</option></select></div>
                <div className="relative group">{monitoringAttendanceFilter === 'not-attended' ? <UserX className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-red-500" /> : <UserCheck className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-indigo-500 transition-colors" />}<select className="w-full bg-[#1a1a1e] border border-white/10 rounded-2xl py-4 pl-14 pr-6 text-white text-sm outline-none focus:border-indigo-600 transition-all appearance-none cursor-pointer" value={monitoringAttendanceFilter} onChange={e => setMonitoringAttendanceFilter(e.target.value as any)}><option value="all">Barcha Davomat</option><option value="attended">Qatnashganlar</option><option value="not-attended">Qatnashmaganlar</option></select></div>
                <div className="flex items-center justify-end gap-3"><button onClick={() => { setMonitoringSearch(''); setMonitoringCuratorFilter('all'); setMonitoringStatusFilter('all'); setMonitoringAttendanceFilter('all'); }} className="px-6 py-4 bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/5">Tozalash</button></div>
             </div>
             <div className="glass rounded-[3.5rem] border border-white/10 shadow-2xl bg-[#0a0a0c]/60 backdrop-blur-3xl overflow-hidden"><div className="overflow-x-auto"><table className="w-full text-left border-collapse min-w-[1200px]"><thead><tr className="bg-white/[0.04] border-b border-white/5"><th className="px-10 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[20%]">O'quvchi & Kurator</th><th className="px-6 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[20%]">Maqsad</th><th className="px-6 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[16%]">Muammo</th><th className="px-6 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[18%]">Yechim</th><th className="px-6 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[12%]">Holat</th><th className="px-10 py-10 text-[10px] font-black text-slate-500 uppercase tracking-widest w-[10%] text-center">Ishtirok</th></tr></thead><tbody className="divide-y divide-white/5">{paginatedMonitoring.length > 0 ? paginatedMonitoring.map(item => { const curator = allUsers.find(u => u.id === item.curatorId); const student = allUsers.find(u => u.name === item.studentName); return (<tr key={item.id} className="hover:bg-indigo-600/[0.03] transition-all duration-300"><td className="px-10 py-9"><div className="relative pl-4 space-y-3"><div className="absolute left-0 top-2 bottom-2 w-0.5 bg-indigo-500/20 rounded-full"></div><div className="flex items-center gap-4 cursor-pointer group/name" onClick={() => student && setSelectedUserForView(student)}><div className="w-10 h-10 rounded-xl bg-indigo-600/10 border border-indigo-500/10 flex items-center justify-center text-xs text-indigo-400 font-black group-hover/name:bg-indigo-600 group-hover/name:text-white transition-all shadow-sm">{item.studentName[0]}</div><div><p className="text-base font-black text-white tracking-tight group-hover/name:text-indigo-400 transition-colors">{item.studentName}</p><p className="text-[10px] text-slate-600 font-bold uppercase tracking-widest">O'quvchi</p></div></div><div className="flex items-center gap-3 pl-1 cursor-pointer group/curator" onClick={() => curator && setSelectedUserForView(curator)}><div className="flex items-center justify-center w-5 h-5 bg-white/5 rounded-full"><Link2 className="w-2.5 h-2.5 text-indigo-400/50 group-hover/curator:text-indigo-400 transition-colors" /></div><span className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter group-hover/curator:text-slate-300 transition-colors">Kurator: {curator?.name || 'Noma\'lum'}</span></div></div></td><td className="px-6 py-9"><p className="text-sm text-slate-300 leading-relaxed font-medium bg-white/[0.02] p-4 rounded-2xl border border-white/5">{item.weeklyGoal}</p></td><td className="px-6 py-9"><div className={`flex items-start gap-3 p-4 rounded-2xl border transition-all ${item.difficulty === 'Yo\'q' ? 'bg-white/[0.01] border-white/5 opacity-40' : 'bg-orange-500/5 border-orange-500/10'}`}>{item.difficulty !== 'Yo\'q' && <AlertTriangle className="w-4 h-4 text-orange-500 shrink-0 mt-0.5" />}<p className={`text-sm leading-relaxed ${item.difficulty === 'Yo\'q' ? 'text-slate-500 font-medium' : 'text-orange-300 font-bold'}`}>{item.difficulty}</p></div></td><td className="px-6 py-9"><div className="flex items-start gap-3 p-4 bg-green-500/5 border border-green-500/10 rounded-2xl"><Lightbulb className="w-4 h-4 text-green-500 shrink-0 mt-0.5" /><p className="text-sm text-green-200/80 italic leading-relaxed font-medium">{item.solution}</p></div></td><td className="px-6 py-9"><span className={`px-5 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest border transition-all shadow-sm ${getProgressStatusStyle(item.status as any)}`}>{item.status}</span></td><td className="px-10 py-9 text-center"><div className={`w-12 h-12 rounded-full mx-auto flex items-center justify-center transition-all ${item.attended ? 'bg-green-500/10 text-green-500 border border-green-500/20' : 'bg-red-500/5 text-red-500/20 border border-red-500/10'}`}>{item.attended ? <CheckCircle2 className="w-6 h-6" /> : <XCircle className="w-6 h-6" />}</div></td></tr>); }) : (<tr><td colSpan={6} className="py-40 text-center text-slate-700 font-black uppercase tracking-[0.2em] text-xs">Ma'lumotlar mavjud emas</td></tr>)}</tbody></table></div></div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="space-y-10 animate-in fade-in duration-700">
             <div className="flex flex-col lg:flex-row items-center justify-between gap-8 bg-[#121214] p-6 md:p-10 rounded-[3rem] border border-white/5 shadow-2xl">
                <div className="flex-1 w-full max-w-2xl relative group"><Search className="absolute left-8 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-500 group-focus-within:text-indigo-500 transition-colors" /><input type="text" placeholder="A'zoni qidirish..." className="w-full bg-[#0a0a0c] border border-white/10 rounded-[2.5rem] py-6 pl-20 pr-8 text-white text-base outline-none focus:border-indigo-600 transition-all" value={usersSearchQuery} onChange={e => setUsersSearchQuery(e.target.value)} /></div>
                <div className="flex flex-wrap justify-center p-1.5 bg-[#0a0a0c] rounded-[2.5rem] border border-white/10">{(['all', 'student', 'curator', 'admin'] as const).map(r => (<button key={r} onClick={() => setUsersFilterRole(r)} className={`px-8 py-3.5 rounded-[2rem] text-[9px] font-black uppercase tracking-widest transition-all ${usersFilterRole === r ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}>{r === 'all' ? 'Barchasi' : r}</button>))}</div>
             </div>
