600 transition-all h-32 resize-none" placeholder="Bu yerga yozing..." value={directMessageForm.message} onChange={e => setDirectMessageForm({...directMessageForm, message: e.target.value})} /></div><button onClick={handleSendDirectMessage} disabled={isSending || !directMessageForm.title || !directMessageForm.message} className="w-full py-5 bg-indigo-600 text-white rounded-3xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50">{isSending ? <Clock className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}Yuborish</button><button onClick={() => setIsDirectMessaging(false)} className="w-full py-4 text-slate-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-all">Bekor qilish</button></div></div>
                             )}
