  customMembers?: TeamMember[];
  studentsData?: StudentProgress[];
  highlights?: WeeklyHighlight[];
  seasons?: Season[];
  activeSeasonId?: string;
}

const Team: React.FC<TeamProps> = ({ user, onAssignCurator, customMembers, studentsData = [], highlights = [], seasons = [], activeSeasonId = '1' }) => {
