                                </div>
                                <h2 className="text-5xl md:text-7xl font-black text-white tracking-tighter leading-none">{selectedUserForView.name}</h2>
                                <p className="text-2xl md:text-3xl font-bold text-slate-500 tracking-tight">@{selectedUserForView.username}</p>
                             </div>
                          </div>
                       </div>

                       <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                          <div className="lg:col-span-2 space-y-8">
                             <div className="space-y-4">
                                <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3"><FileText className="w-5 h-5 text-indigo-500" /> Professional Bio</h4>
                                <div className="relative p-10 bg-[#121214]/50 border border-white/5 rounded-[2.5rem]">
                                   <p className="text-xl md:text-2xl text-slate-300 leading-relaxed font-medium italic relative z-10">"{selectedUserForView.longBio || 'Ma\'lumot kiritilmagan.'}"</p>
                                </div>
                             </div>
                          </div>
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        )}

        {selectedImage && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 md:p-6 bg-black/98 backdrop-blur-2xl animate-in fade-in duration-300" onClick={() => setSelectedImage(null)}><button className="absolute top-6 right-6 p-4 bg-white/10 text-white rounded-full hover:bg-white/20 transition-all shadow-2xl"><X className="w-8 h-8 md:w-10 md:h-10" /></button><img src={selectedImage} className="max-w-full max-h-[85vh] object-contain rounded-2xl md:rounded-[3rem] shadow-3xl border border-white/10" alt="Full view" /></div>
        )}
      </div>
    </section>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Trash2, Edit2, Save, X, Quote, Plus, Settings, Activity, Users, 
  ChevronLeft, ChevronRight, Calendar, Camera, Maximize2, 
  UploadCloud, Layout, User, Clock, Lock, UserCircle, Target, AlertCircle, Lightbulb, UserCheck, UserX, History, Bookmark, Award, BarChart3, TrendingUp, CheckCircle2, ChevronRight as ChevronRightIcon, Link2, ExternalLink, Zap, Code, FileText, Bell, Info, Image as ImageIcon, Sparkles
} from 'lucide-react';
import { UserData } from '../App';
import { StudentProgress, WeeklyHighlight, Season, Notification } from '../types';

interface DashboardProps {
  user: UserData | null;
  studentsData: StudentProgress[];
  highlights: WeeklyHighlight[];
  onRemoveStudent: (id: string) => void;
  onUpdateProfile: (data: Partial<UserData>) => void;
  onUpdateStudent: (student: StudentProgress) => void;
  onAddProgress: (progress: StudentProgress) => void;
  onAddHighlight: (highlight: WeeklyHighlight) => void;
  onRemoveHighlight: (id: string) => void;
  activeSeasonId: string;
  seasons: Season[];
  notifications?: Notification[];
  onMarkRead?: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  studentsData, 
  highlights,
  onRemoveStudent, 
  onUpdateProfile, 
  onUpdateStudent, 
  onAddProgress,
  onAddHighlight,
  onRemoveHighlight,
  activeSeasonId,
  seasons,
  notifications = [],
  onMarkRead
}) => {
  const [activeTab, setActiveTab] = useState<'panel' | 'profile' | 'notifications'>('panel');
  const [selectedWeek, setSelectedWeek] = useState(1);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [selectedUserForView, setSelectedUserForView] = useState<UserData | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const unreadCount = useMemo(() => notifications.filter(n => !n.isRead).length, [notifications]);

  const canUpload = user?.role === 'curator' || user?.role === 'admin';

  // Enhanced Body and Html scroll lock effect for Dashboard
  useEffect(() => {
    if (selectedUserForView) {
      document.body.style.overflow = 'hidden';
      document.documentElement.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
    };
  }, [selectedUserForView]);

  // Profile Editing State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [profileForm, setProfileForm] = useState({
    name: user?.name || '',
    field: user?.field || '',
    longBio: user?.longBio || '',
    motivationQuote: user?.motivationQuote || '',
    skills: user?.skills?.join(', ') || ''
  });

  const handleSaveProfile = () => {
    onUpdateProfile({
      name: profileForm.name,
      field: profileForm.field,
      longBio: profileForm.longBio,
      motivationQuote: profileForm.motivationQuote,
      skills: profileForm.skills.split(',').map(s => s.trim()).filter(s => s !== '')
    });
    setIsEditingProfile(false);
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && user) {
        if (!file.type.startsWith('image/')) {
            alert('Faqat rasm (image) yuklashingiz mumkin!');
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            const newHighlight: WeeklyHighlight = {
                id: Date.now().toString(),
                curatorId: user.id, // Uploaded by current user
                seasonId: activeSeasonId,
                weekNumber: selectedWeek,
                photoUrl: reader.result as string,
                uploadedBy: user.name
            };
            onAddHighlight(newHighlight);
            // Reset input
            if (fileInputRef.current) fileInputRef.current.value = '';
        };
        reader.readAsDataURL(file);
    }
  };

  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Hal qilindi': return 'bg-green-500/10 text-green-400 border-green-500/20';
      case 'Bajarmadi': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'Bajarilmoqda': return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
      case 'Kutilmoqda': return 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20';
      default: return 'bg-white/10 text-white border-white/20';
    }
  };

  const getRoleStyle = (role: string) => {
    switch(role) {
      case 'admin': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'curator': return 'bg-purple-500/10 text-purple-400 border-purple-500/20';
      default: return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
    }
  };

  const getNotificationIcon = (type: Notification['type']) => {
    switch(type) {
      case 'info': return <Info className="w-5 h-5 text-blue-400" />;
      case 'success': return <CheckCircle2 className="w-5 h-5 text-green-400" />;
      case 'warning': return <AlertCircle className="w-5 h-5 text-yellow-400" />;
      case 'urgent': return <Zap className="w-5 h-5 text-red-500 animate-pulse" />;
      default: return <Bell className="w-5 h-5 text-indigo-400" />;
    }
  };

  const mySeasonProgress = useMemo(() => {
    const base = user?.role === 'curator' ? studentsData.filter(s => s.curatorId === user.id) : [];
    // Student logic: show their own progress
    if (user?.role === 'student') {
        return studentsData.filter(s => s.studentName === user.name && s.seasonId === activeSeasonId);
    }
    return base.filter(s => s.seasonId === activeSeasonId);
  }, [studentsData, user, activeSeasonId]);

  const filteredProgress = useMemo(() => {
    return mySeasonProgress.filter(p => p.weekNumber === selectedWeek);
  }, [mySeasonProgress, selectedWeek]);

  const filteredHighlights = useMemo(() => {
    if (user?.role === 'curator') {
       return highlights.filter(h => 
          h.curatorId === user.id && 
          h.seasonId === activeSeasonId && 
          h.weekNumber === selectedWeek
       );
    }
    if (user?.role === 'admin') {
        return highlights.filter(h => 
            h.seasonId === activeSeasonId && 
            h.weekNumber === selectedWeek
        );
    }
    if (user?.role === 'student' && user.assignedCuratorId) {
        return highlights.filter(h => 
            h.curatorId === user.assignedCuratorId && 
            h.seasonId === activeSeasonId && 
            h.weekNumber === selectedWeek
        );
    }
    // Fallback: show nothing or generic highlights if any
    return [];
  }, [highlights, user, activeSeasonId, selectedWeek]);

  const uniqueStudents = useMemo(() => {
    const names = Array.from(new Set(mySeasonProgress.map(s => s.studentName)));
    return names.map(name => {
      const studentData = mySeasonProgress.find(s => s.studentName === name);
      return { id: studentData?.id || `temp-${name}`, name: name };
    });
  }, [mySeasonProgress]);

  const formatMeetingDay = (val: string) => {
    if (!val) return "Belgilanmagan";
    try {
      const date = new Date(val);
      return date.toLocaleString('uz-UZ', { 
        weekday: 'short', day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' 
      });
    } catch { return val; }
  };

  return (
    <section id="dashboard" className="py-10 md:py-20 bg-[#0a0a0c] min-h-screen">
      <div className="max-w-[1800px] mx-auto px-4 lg:px-10">

        {/* Navigation Tabs */}
        <div className="flex justify-center mb-10 md:mb-16">
          <div className="inline-flex p-1.5 bg-white/5 rounded-[2.5rem] border border-white/10 backdrop-blur-2xl">
            {/* SWAPPED: Notifications is now first */}
            <button 
              onClick={() => setActiveTab('notifications')}
              className={`flex items-center space-x-3 px-8 py-4 rounded-3xl text-[10px] font-black transition-all relative ${
                activeTab === 'notifications' ? 'bg-purple-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
              }`}
            >
              <Bell className="w-4 h-4" />
              <span className="uppercase tracking-widest">Bildirishnomalar</span>
              {unreadCount > 0 && (
                <span className="absolute top-2 right-2 w-5 h-5 bg-red-500 text-white text-[8px] flex items-center justify-center rounded-full font-black border-2 border-[#0a0a0c]">
                  {unreadCount}
                </span>
              )}
            </button>

            {/* SWAPPED: Monitoring is now second */}
            <button 
              onClick={() => setActiveTab('panel')}
              className={`flex items-center space-x-3 px-8 py-4 rounded-3xl text-[10px] font-black transition-all ${
                activeTab === 'panel' ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
              }`}
            >
              <Activity className="w-4 h-4" />
              <span className="uppercase tracking-widest">Monitoring</span>
            </button>

            <button 
              onClick={() => setActiveTab('profile')}
              className={`flex items-center space-x-3 px-8 py-4 rounded-3xl text-[10px] font-black transition-all ${
                activeTab === 'profile' ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white'
              }`}
            >
              <Settings className="w-4 h-4" />
              <span className="uppercase tracking-widest">Profil</span>
            </button>
          </div>
