                  </div>
               </div>
            </div>
          </div>
        )}
        {selectedImage && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 md:p-6 bg-black/98 backdrop-blur-2xl animate-in fade-in duration-300" onClick={() => setSelectedImage(null)}><button className="absolute top-6 right-6 p-4 bg-white/10 text-white rounded-full hover:bg-white/20 transition-all shadow-2xl"><X className="w-8 h-8 md:w-10 md:h-10" /></button><img src={selectedImage} className="max-w-full max-h-[85vh] object-contain rounded-2xl md:rounded-[3rem] shadow-3xl border border-white/10" alt="Full view" /></div>
        )}
      </div>
    </div>
  );
};

