const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  studentsData, 
  highlights,
  onRemoveStudent, 
  onUpdateProfile, 
  onUpdateStudent, 
  onAddProgress,
  onAddHighlight,
  onRemoveHighlight,
  activeSeasonId,
  seasons,
  notifications = [],
