                                       </div>
                                    )}
                                </div>
                            ) : (
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <div className="text-center max-w-sm px-6">
                                        <div className="w-20 h-20 bg-white/5 rounded-[2rem] flex items-center justify-center mx-auto mb-6 border border-white/5 relative">
                                            <ImageIcon className="w-8 h-8 text-slate-600" />
                                            <div className="absolute -top-2 -right-2 w-6 h-6 bg-purple-500/20 rounded-full flex items-center justify-center border border-purple-500/30">
                                               <Info className="w-3 h-3 text-purple-400" />
                                            </div>
                                        </div>
                                        <h4 className="text-xl font-black text-white mb-2">Hozircha bo'shliq</h4>
                                        <p className="text-slate-500 text-sm leading-relaxed mb-6">
                                            Hafta #0{selectedWeek} uchun hali hech qanday rasm yuklanmagan. 
                                            {canUpload ? " Birinchi bo'lib siz yuklang!" : " Kuratorlar tez orada yuklashadi."}
                                        </p>
                                        {canUpload && (
                                            <button 
                                                onClick={() => fileInputRef.current?.click()}
                                                className="px-6 py-3 bg-purple-600 hover:bg-purple-500 text-white rounded-xl font-bold text-xs transition-all shadow-lg shadow-purple-600/20"
                                            >
                                                Rasm Yuklash
                                            </button>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                 </div>
               </>
             )}
          </div>
        )}

        {/* NOTIFICATIONS TAB */}
        {activeTab === 'notifications' && (
           <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in duration-500">
              <div className="flex items-center justify-between">
                 <h2 className="text-4xl font-black text-white flex items-center gap-4">
                    <Bell className="w-10 h-10 text-purple-400" /> Bildirishnomalar
                 </h2>
                 <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">
                    Jami {notifications.length} ta xabar
                 </span>
              </div>

              <div className="space-y-6">
                 {notifications.length > 0 ? notifications.map((notif) => (
                    <div 
                       key={notif.id}
                       onClick={() => onMarkRead?.(notif.id)}
                       className={`relative p-8 rounded-[2.5rem] border transition-all cursor-pointer group ${
                          notif.isRead 
                          ? 'bg-white/[0.02] border-white/5 opacity-70' 
                          : 'bg-indigo-600/[0.04] border-indigo-500/20 shadow-2xl'
                       }`}
                    >
                       {!notif.isRead && (
                          <div className="absolute top-6 right-6 w-3 h-3 bg-indigo-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(99,102,241,0.8)]"></div>
                       )}

                       <div className="flex items-start gap-6">
                          <div className={`p-4 rounded-2xl shrink-0 ${
                             notif.type === 'urgent' ? 'bg-red-500/10' : 
                             notif.type === 'success' ? 'bg-green-500/10' : 
                             notif.type === 'warning' ? 'bg-orange-500/10' : 'bg-blue-500/10'
                          }`}>
                             {getNotificationIcon(notif.type)}
                          </div>

                          <div className="flex-1">
                             <div className="flex items-center justify-between mb-2">
                                <h3 className="text-xl font-black text-white group-hover:text-indigo-400 transition-colors">
                                   {notif.title}
                                </h3>
                                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
                                   {new Date(notif.timestamp).toLocaleDateString()}
                                </span>
                             </div>
                             <p className="text-slate-400 leading-relaxed font-medium">
                                {notif.message}
                             </p>
                             <div className="mt-4 flex items-center gap-2">
                                <span className="text-[9px] font-black text-slate-700 uppercase tracking-[0.2em]">Yuboruvchi:</span>
                                <span className="text-[9px] font-black text-indigo-400 uppercase tracking-widest">{notif.sender}</span>
                             </div>
                          </div>
                       </div>
                    </div>
                 )) : (
                    <div className="py-32 text-center glass rounded-[3rem] border-dashed border-2 border-white/5">
                       <Bell className="w-16 h-16 text-slate-800 mx-auto mb-6 opacity-20" />
                       <p className="text-xl font-black text-slate-700 uppercase tracking-widest">Hozircha bildirishnomalar yo'q</p>
                    </div>
                 )}
              </div>
           </div>
        )}

        {/* ULTRA-PREMIUM USER DETAIL MODAL IN DASHBOARD */}
        {selectedUserForView && (
           <div className="fixed inset-0 z-[300] bg-black/90 backdrop-blur-3xl overflow-y-auto py-10 px-4 md:px-10 animate-in fade-in zoom-in duration-500">
              <div className="flex min-h-full items-center justify-center">
                 <div className="glass w-full max-w-5xl border border-white/10 rounded-[3rem] md:rounded-[4.5rem] relative shadow-[0_0_100px_rgba(79,70,229,0.15)] overflow-hidden">
                    <button onClick={() => setSelectedUserForView(null)} className="absolute top-8 right-8 p-3.5 bg-white/5 text-slate-400 hover:text-white hover:bg-red-500/20 rounded-full transition-all border border-white/5 z-30 group">
                       <X className="w-6 h-6 group-hover:rotate-90 transition-transform" />
                    </button>

                    <div className="p-8 md:p-16">
                       <div className="flex flex-col lg:flex-row items-center gap-12 mb-16 border-b border-white/5 pb-16">
                          <div className="relative group shrink-0">
                             <div className="w-44 h-44 md:w-56 md:h-56 rounded-[3.5rem] md:rounded-[4.5rem] bg-[#121214] border-4 border-white/5 overflow-hidden flex items-center justify-center text-indigo-400 text-7xl font-black shadow-2xl relative z-10 transition-transform group-hover:scale-[1.02] duration-500">
                                {selectedUserForView.avatar ? <img src={selectedUserForView.avatar} className="w-full h-full object-cover" alt={selectedUserForView.name} /> : selectedUserForView.name[0]}
                             </div>
                          </div>

                          <div className="text-center lg:text-left flex-1 space-y-6">
                             <div className="space-y-2">
                                <div className="flex flex-wrap items-center justify-center lg:justify-start gap-3 mb-2">
                                   <span className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border shadow-sm ${getRoleStyle(selectedUserForView.role)}`}>{selectedUserForView.role}</span>
                                </div>
                                <h2 className="text-5xl md:text-7xl font-black text-white tracking-tighter leading-none">{selectedUserForView.name}</h2>
                                <p className="text-2xl md:text-3xl font-bold text-slate-500 tracking-tight">@{selectedUserForView.username}</p>
                             </div>
                          </div>
                       </div>

                       <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                          <div className="lg:col-span-2 space-y-8">
                             <div className="space-y-4">
                                <h4 className="text-[11px] font-black uppercase text-slate-500 tracking-[0.4em] flex items-center gap-3"><FileText className="w-5 h-5 text-indigo-500" /> Professional Bio</h4>
                                <div className="relative p-10 bg-[#121214]/50 border border-white/5 rounded-[2.5rem]">
                                   <p className="text-xl md:text-2xl text-slate-300 leading-relaxed font-medium italic relative z-10">"{selectedUserForView.longBio || 'Ma\'lumot kiritilmagan.'}"</p>
                                </div>
                             </div>
                          </div>
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        )}

        {selectedImage && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 md:p-6 bg-black/98 backdrop-blur-2xl animate-in fade-in duration-300" onClick={() => setSelectedImage(null)}><button className="absolute top-6 right-6 p-4 bg-white/10 text-white rounded-full hover:bg-white/20 transition-all shadow-2xl"><X className="w-8 h-8 md:w-10 md:h-10" /></button><img src={selectedImage} className="max-w-full max-h-[85vh] object-contain rounded-2xl md:rounded-[3rem] shadow-3xl border border-white/10" alt="Full view" /></div>
        )}
      </div>
    </section>
  );
};

export default Dashboard;
